arguments.argument:
if global.gamePaused=false
{
  if bCanMove=true
  {
    shiftTime+=1
    if moveProg=0 //right
    {
      xVel=shiftSpd
      yVel=0
      if shiftTime>=timeRight
      {
        shiftTime=0
        if bReverse=0
          moveProg+=1
        else
          moveProg=3
      }
    }
    else if moveProg=1 //down
    {
      xVel=0
      yVel=shiftSpd
      if shiftTime>=timeDown
      {
        shiftTime=0
        if bReverse=0
          moveProg+=1
        else
          moveProg-=1
      }
    }
    else if moveProg=2 //left
    {
      xVel=-shiftSpd
      yVel=0
      if shiftTime>=timeLeft
      {
        shiftTime=0
        if bReverse=0
          moveProg+=1
        else
          moveProg-=1
      }
    }
    else if moveProg=3 //up
    {
      xVel=0
      yVel=-shiftSpd
      if shiftTime>=timeUp
      {
        shiftTime=0
        if bReverse=0
          moveProg=0
        else
          moveProg-=1
      }
    }
  }
}
